const PROCESSING_FEE = 5;

const NEWCOMER_PREMIUM_BY_TYPE: Record<string, number> = {
  potion: 49,
  amulet: 71,
};

export function quote(input: { customer: { yearsWithMHPCO: number }; items: { type: string }[] }): number {
  if (input.items.length === 0) return PROCESSING_FEE;
  return NEWCOMER_PREMIUM_BY_TYPE[input.items[0].type];
}
